                int newSize = entry.getValue();

                int currentMax = map2.getOrDefault(newXorSum, -1);
                if (newSize > currentMax) {
                    map2.put(newXorSum, newSize);
                }
            }
        }

        // --- Combine Results ---
        // We need (XOR_sum1 ^ XOR_sum2) = target
        // Which means XOR_sum2 = target ^ XOR_sum1

