function solve(nums, target) {
    const n = nums.length;
    let minRemovals = Infinity;

    // The problem asks for the minimum number of removals, which is equivalent to
    // maximizing the number of kept elements such that their XOR sum is 'target'.
    // Number of removals = Total length - Number of kept elements.
    // We iterate through all possible subsets using bitmasks.
    // Since N <= 40, 2^40 is too large for a direct subset iteration.

    // Let's re-examine the constraints and the goal.
    // N <= 40 suggests an exponential solution might be too slow, but maybe meet-in-the-middle (2^(N/2)).
    // N/2 = 20, 2^20 is about 1 million, which is feasible.

    const N1 = Math.floor(n / 2);
    const N2 = n - N1;

    // --- First Half (nums[0] to nums[N1-1]) ---
    // Map: { xor_sum: [list_of_possible_subset_sizes] }
    // We only care about the maximum subset size for a given XOR sum.
    // Map: { xor_sum: max_size }
    const map1 = new Map();
    map1.set(0, 0); // Empty set: XOR sum 0, size 0

    for (let i = 0; i < N1; i++) {
        const num = nums[i];
        const updates = [];
        for (const [xorSum, maxSize] of map1.entries()) {
            const newXorSum = xorSum ^ num;
            const newSize = maxSize + 1;
            updates.push({ newXorSum, newSize });
        }

        for (const { newXorSum, newSize } of updates) {
            const currentMax = map1.get(newXorSum) || -1;
            if (newSize > currentMax) {
                map1.set(newXorSum, newSize);
            }
        }
    }

    // --- Second Half (nums[N1] to nums[n-1]) ---
    const map2 = new Map();
    map2.set(0, 0); // Empty set: XOR sum 0, size 0

    for (let i = N1; i < n; i++) {
        const num = nums[i];
        const updates = [];
        for (const [xorSum, maxSize] of map2.entries()) {
            const newXorSum = xorSum ^ num;
            const newSize = maxSize + 1;
            updates.push({ newXorSum, newSize });
        }

        for (const { newXorSum, newSize } of updates) {
            const currentMax = map2.get(newXorSum) || -1;
            if (newSize > currentMax) {
                map2.set(newXorSum, newSize);
            }
        }
    }

    // --- Combine Results ---
    // We need (XOR_sum1 ^ XOR_sum2) = target
    // Which means XOR_sum2 = target ^ XOR_sum1

    let maxKeptElements = -1;

    for (const [xorSum1, size1] of map1.entries()) {
        const neededXorSum2 = target ^ xorSum1;

        if (map2.has(neededXorSum2)) {
            const size2 = map2.get(neededXorSum2);
            const totalSize = size1 + size2;
            if (totalSize > maxKeptElements) {
                maxKeptElements = totalSize;
            }
        }
    }

    if (maxKeptElements === -1) {
        return -1;
    }

    // Minimum removals = Total elements - Maximum kept elements
    return n - maxKeptElements;
}

