        for (int i = 0; i < N1; i++) {
            long num = nums[i];
            // Use a temporary map to store updates to avoid concurrent modification issues
            Map<Long, Integer> updates = new HashMap<>();

            for (Map.Entry<Long, Integer> entry : map1.entrySet()) {
                long xorSum = entry.getKey();
                int maxSize = entry.getValue();

                long newXorSum = xorSum ^ num;
                int newSize = maxSize + 1;

                // Update the temporary map if this new state is better (larger size)
                updates.merge(newXorSum, newSize, Math::max);
            }

            // Apply updates to map1
            for (Map.Entry<Long, Integer> entry : updates.entrySet()) {
                long xorSum = entry.getKey();
