                int newSize = entry.getValue();

                map2.merge(xorSum, newSize, Math::max);
            }
        }

        // --- Combine Results ---
        // We need (XOR_sum1 ^ XOR_sum2) = target
        // Which means XOR_sum2 = target ^ XOR_sum1

        int maxKeptElements = -1;

        for (Map.Entry<Long, Integer> entry1 : map1.entrySet()) {
